  var currTrial = {
    trialNum: globalStore.trialNum,
    intendedName: (globalStore.trialNum % 2) == 0 ? 'bluecircle' : 'redsquare',
    context : objects,
    speakerID: (repNum % 2) == 0 ? 1 : 2,
    listenerID: (repNum % 2) == 0 ? 2 : 1
  };

